var e=[{id:`L3_1`,type:`dialog`,speaker:`SOMI_DAYMINE_NULL_NULL`,text:{KOREA:`우, 우왓!`,JPN:`わ、わっ！`,ENG:`W-whoa!`,TWN:`哇！`},stage:{bg:`CITY_CENTER1`,slots:{L:null,C:{char_id:`SOMI_DAYMINE_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`SOMI_DAYMINE_NULL_NULL`,text:{KOREA:`아하하…… 이, 이건 나 혼자서는 도저히…….`,JPN:`あはは……こ、これは私一人では無理かも……`,ENG:`Ahaha... I-I can’t handle this all by myself...`,TWN:`哈哈哈……我自己是要怎麼……`},stage:{bg:`CITY_CENTER1`,slots:{L:null,C:{char_id:`SOMI_DAYMINE_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`JIA_ALPHA_NULL_NULL`,text:{KOREA:`그쪽 여성 분!! 제 뒤로 오세요!!`,JPN:`そちらの女性の方！！　私の後ろに来てください！！`,ENG:`You, over there! Get behind me!!`,TWN:`那位小姐！！請到我身後來！！`},stage:{bg:`CITY_CENTER1`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`JIA_ALPHA_NULL_NULL`,text:{KOREA:`다행이다……. 늦지 않았네요.`,JPN:`よかった……間に合ったようですね。`,ENG:`Thank goodness... What a close call.`,TWN:`好險……還來得及。`},stage:{bg:`CITY_CENTER1`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`JIA_ALPHA_NULL_NULL`,text:{KOREA:`다치진 않으셨어요?`,JPN:`お怪我はありませんか？`,ENG:`Are you okay?`,TWN:`你沒受傷吧？`},stage:{bg:`CITY_CENTER1`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`SOMI_DAYMINE_NULL_NULL`,text:{KOREA:`수, 순식간에…… 해치워버렸어……!!`,JPN:`あ、あっという間に……やっつけた……！！`,ENG:`S-she took them out so easily...!!`,TWN:`立…立刻……就處理掉咧……！！`},stage:{bg:`CITY_CENTER1`,slots:{L:null,C:{char_id:`SOMI_DAYMINE_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`SOMI_DAYMINE_NULL_NULL`,text:{KOREA:`고맙습니다, 멋진 언니……! 저도 언니처럼 되고 싶어요!`,JPN:`ありがとうございます、素敵なお姉さん……！
私もお姉さんみたいになりたいですっ！`,ENG:`Thank you...! I want to be like you someday!`,TWN:`謝謝你，帥氣的姊姊……！我也想跟姊姊一樣！`},stage:{bg:`CITY_CENTER1`,slots:{L:null,C:{char_id:`SOMI_DAYMINE_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`JIA_ALPHA_NULL_NULL`,text:{KOREA:`…….`,JPN:`……`,ENG:`...`,TWN:`……`},stage:{bg:`CITY_CENTER1`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`GUARD_NPC_ALPHA_NULL`,text:{KOREA:`아가씨……. 왜 저를…….`,JPN:`お嬢様……なぜ私を……`,ENG:`Miss Jia... W-why did you...?`,TWN:`小姐……為什麼要救我……`},stage:{bg:`HANGAR`,slots:{L:null,C:{char_id:`GUARD_NPC_ALPHA_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`JIA_ALPHA_NULL_NULL`,text:{KOREA:`할아버님은 직원의 일도 자기 일처럼 생각하라고 하셨거든요.`,JPN:`お祖父様は、社員のことは自分の事のように考えなさいとおっしゃいました。`,ENG:`Grandfather said to treat employees how I would want them to treat me.`,TWN:`我爺爺有說，要把員工的事當成自己的事。`},stage:{bg:`HANGAR`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`JIA_ALPHA_NULL_NULL`,text:{KOREA:`제가 다치기 싫은 것처럼, 대장님도 다치기 싫으셨을 거예요.`,JPN:`私が怪我をしたくないように、隊長も怪我をしたくないはずだと思っただけです。`,ENG:`Much like I dislike getting hurt, I bet you wouldn’t like it as well.`,TWN:`我不想受傷的話，那你應該也不想受傷吧。`},stage:{bg:`HANGAR`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`ELECTRONICSCEO_NPC_ALPHA_NULL`,text:{KOREA:`네…… 네가 날 살린 건가? 윽……!`,JPN:`お……お前が私を助けたのか？　うっ……！`,ENG:`Y-you... saved me? Ngh...!`,TWN:`是……你救了我的嗎？嗚……！`},stage:{bg:`WORKSHOP`,slots:{L:null,C:null,R:null}}},{id:`L22_1`,type:`dialog`,speaker:`JIA_ALPHA_NULL_NULL`,text:{KOREA:`총알이 어깨를 스쳐 지나갔어요. 다행히 큰 부상은 아니네요.`,JPN:`弾丸が肩をかすめています。
幸い、大事に至るような怪我ではありません。`,ENG:`The bullet grazed your shoulder. Luckily, it’s not fatal.`,TWN:`子彈劃過你的肩膀，幸好沒有大礙。`},stage:{bg:`WORKSHOP`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L24_1`,type:`dialog`,speaker:`ELECTRONICSCEO_NPC_ALPHA_NULL`,text:{KOREA:`……고맙군. 내가 큰 착각을 하고 있었어.`,JPN:`……ありがとう。私は大きな勘違いをしていたようだ。`,ENG:`Thank you... It seems that I was wrong about you.`,TWN:`……謝謝你，我誤會你了。`},stage:{bg:`WORKSHOP`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`SOMI_DAYMINE_NULL_NULL`,text:{KOREA:`언니……?`,JPN:`お姉さん……？`,ENG:`Hello...? Miss?`,TWN:`姊姊……？`},stage:{bg:`CITY_CENTER1`,slots:{L:null,C:{char_id:`SOMI_DAYMINE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`JIA_ALPHA_NULL_NULL`,text:{KOREA:`아.`,JPN:`あ。`,ENG:`Oh.`,TWN:`喔！`},stage:{bg:`CITY_CENTER1`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}}];export{e as default};